/**
 * Build DATABASE_URL from bootstrap secret fields and/or Supabase Management API.
 *
 * Pooler hostnames (e.g. aws-0-us-east-1 vs aws-1-us-east-1) are project-specific;
 * do not synthesize them from region.
 */

export function trim(s) {
  return (s ?? '').trim();
}

export function die(msg, prefix = 'build-bootstrap-database-url') {
  console.error(`[${prefix}] ${msg}`);
  process.exit(1);
}

function managementToken() {
  return trim(process.env.REBASE_SUPABASE_ACCESS_TOKEN) || trim(process.env.SUPABASE_ACCESS_TOKEN);
}

function managementApiBase() {
  return trim(process.env.SUPABASE_MANAGEMENT_API_URL) || 'https://api.supabase.com/v1';
}

function encodeDatabaseUrl({ user, password, host, port, database }) {
  const enc = encodeURIComponent(password);
  return `postgresql://${user}:${enc}@${host}:${port}/${database}`;
}

function poolerUserForRef(ref) {
  return `postgres.${ref}`;
}

function directUser() {
  return 'postgres';
}

function readStoredPoolerTarget(data) {
  const host = trim(data.database_pooler_host ?? data.databasePoolerHost);
  const portRaw = data.database_pooler_port ?? data.databasePoolerPort;
  const port = typeof portRaw === 'number' ? portRaw : Number.parseInt(trim(String(portRaw ?? '')), 10);
  const user = trim(data.database_pooler_user ?? data.databasePoolerUser);
  const database = trim(data.database_pooler_database ?? data.databasePoolerDatabase) || 'postgres';
  if (!host || !Number.isFinite(port) || port <= 0) {
    return null;
  }
  return { host, port, user, database };
}

function readStoredDirectTarget(data, ref) {
  const host = trim(data.database_direct_host ?? data.databaseDirectHost) || `db.${ref}.supabase.co`;
  const portRaw = data.database_direct_port ?? data.databaseDirectPort;
  const port =
    typeof portRaw === 'number'
      ? portRaw
      : Number.parseInt(trim(String(portRaw ?? '')), 10) || 5432;
  const user = trim(data.database_direct_user ?? data.databaseDirectUser) || directUser();
  const database = trim(data.database_direct_database ?? data.databaseDirectDatabase) || 'postgres';
  return { host, port, user, database };
}

function pickPoolerRow(rows, mode) {
  if (!Array.isArray(rows)) {
    return null;
  }
  const primary = rows.filter(
    (row) =>
      row &&
      typeof row === 'object' &&
      trim(row.database_type ?? row.databaseType).toUpperCase() === 'PRIMARY',
  );
  const wantMode = mode === 'session' ? 'session' : 'transaction';
  const exact = primary.find((row) => trim(row.pool_mode ?? row.poolMode).toLowerCase() === wantMode);
  if (exact) {
    return exact;
  }
  return primary[0] ?? null;
}

async function fetchPoolerTargetFromApi(ref, mode) {
  const token = managementToken();
  if (!token) {
    return null;
  }
  const url = `${managementApiBase().replace(/\/$/, '')}/projects/${ref}/config/database/pooler`;
  const response = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: 'application/json',
    },
  });
  if (!response.ok) {
    const body = await response.text();
    die(
      `Supabase pooler config fetch failed (${response.status}): ${body.slice(0, 300)}`,
      'build-bootstrap-database-url',
    );
  }
  const rows = await response.json();
  const row = pickPoolerRow(rows, mode);
  if (!row) {
    die(`Supabase pooler config for ${ref} did not include a PRIMARY entry.`);
  }
  const host = trim(row.db_host ?? row.dbHost);
  const portRaw = row.db_port ?? row.dbPort;
  const port = typeof portRaw === 'number' ? portRaw : Number.parseInt(trim(String(portRaw ?? '')), 10);
  const user = trim(row.db_user ?? row.dbUser) || poolerUserForRef(ref);
  const database = trim(row.db_name ?? row.dbName) || 'postgres';
  if (!host || !Number.isFinite(port) || port <= 0) {
    die(`Supabase pooler config for ${ref} is missing db_host/db_port.`);
  }
  return { host, port, user, database };
}

async function fetchDirectTargetFromApi(ref) {
  const token = managementToken();
  if (!token) {
    return null;
  }
  const url = `${managementApiBase().replace(/\/$/, '')}/projects/${ref}`;
  const response = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: 'application/json',
    },
  });
  if (!response.ok) {
    const body = await response.text();
    die(
      `Supabase project fetch failed (${response.status}): ${body.slice(0, 300)}`,
      'build-bootstrap-database-url',
    );
  }
  const detail = await response.json();
  const host = trim(detail.db_host ?? detail.dbHost) || `db.${ref}.supabase.co`;
  const portRaw = detail.db_port ?? detail.dbPort;
  const port =
    typeof portRaw === 'number'
      ? portRaw
      : Number.parseInt(trim(String(portRaw ?? '')), 10) || 5432;
  const user = trim(detail.db_user ?? detail.dbUser) || directUser();
  const database = 'postgres';
  return { host, port, user, database };
}

/**
 * @param {{ ref: string, password: string, raw: Record<string, unknown> }} payload
 * @param {'direct'|'pooler'} mode
 */
export async function buildBootstrapDatabaseUrl(payload, mode) {
  const { ref, password, raw } = payload;
  if (!ref) {
    die('missing supabase_project_ref');
  }
  if (!password) {
    die('missing database_password');
  }
  if (mode !== 'direct' && mode !== 'pooler') {
    die('REBASE_DATABASE_URL_MODE must be direct or pooler');
  }

  if (mode === 'direct') {
    const stored = readStoredDirectTarget(raw, ref);
    const target = stored.host ? stored : (await fetchDirectTargetFromApi(ref)) ?? stored;
    return encodeDatabaseUrl({ ...target, password });
  }

  const poolerMode = trim(process.env.REBASE_DATABASE_POOLER_MODE).toLowerCase() || 'transaction';
  const stored = readStoredPoolerTarget(raw);
  const target =
    stored ?? (await fetchPoolerTargetFromApi(ref, poolerMode === 'session' ? 'session' : 'transaction'));
  if (!target) {
    die(
      'missing database_pooler_host in bootstrap secret; set REBASE_SUPABASE_ACCESS_TOKEN to fetch pooler config from Supabase',
    );
  }
  const user = target.user || poolerUserForRef(ref);
  return encodeDatabaseUrl({ ...target, user, password });
}

export function resolveDatabaseUrlMode() {
  return trim(process.env.REBASE_DATABASE_URL_MODE).toLowerCase() || 'pooler';
}

#!/usr/bin/env node
/**
 * Read bootstrap JSON (stdin or --file) and print selected fields for Cloud Run / GitHub wiring.
 *
 * Usage:
 *   aws secretsmanager get-secret-value ... | node extract-bootstrap-fields.mjs --json
 *   node extract-bootstrap-fields.mjs --file payload.json --field supabase_url
 *
 * Env: REBASE_DATABASE_URL_MODE=direct|pooler (default pooler)
 *      REBASE_SUPABASE_ACCESS_TOKEN / SUPABASE_ACCESS_TOKEN — fetch pooler host when not in secret
 */
import { readFileSync } from 'node:fs';

import {
  buildBootstrapDatabaseUrl,
  die,
  resolveDatabaseUrlMode,
  trim,
} from './build-bootstrap-database-url.mjs';

function parsePayload(raw) {
  let data;
  try {
    data = JSON.parse(raw);
  } catch {
    die('bootstrap JSON is not valid JSON', 'extract-bootstrap-fields');
  }
  if (!data || typeof data !== 'object') {
    die('bootstrap JSON must be an object', 'extract-bootstrap-fields');
  }
  const ref = trim(data.supabase_project_ref ?? data.supabaseProjectRef);
  const password = trim(data.database_password ?? data.databasePassword);
  const supabaseUrl = trim(data.supabase_url ?? data.supabaseUrl);
  const anonKey = trim(data.supabase_anon_key ?? data.supabaseAnonKey);
  if (!ref) die('missing supabase_project_ref', 'extract-bootstrap-fields');
  if (!password) die('missing database_password', 'extract-bootstrap-fields');
  if (!supabaseUrl) die('missing supabase_url', 'extract-bootstrap-fields');
  if (!anonKey) die('missing supabase_anon_key', 'extract-bootstrap-fields');
  return { ref, password, supabaseUrl, anonKey, raw: data };
}

const args = process.argv.slice(2);
const fileIdx = args.indexOf('--file');
const jsonMode = args.includes('--json');
const fieldIdx = args.indexOf('--field');
const fieldName = fieldIdx >= 0 ? trim(args[fieldIdx + 1]) : '';

let raw = '';
if (fileIdx >= 0) {
  const path = args[fileIdx + 1];
  if (!path) die('--file requires a path', 'extract-bootstrap-fields');
  raw = readFileSync(path, 'utf8');
} else {
  raw = readFileSync(0, 'utf8');
}

const mode = resolveDatabaseUrlMode();
const payload = parsePayload(raw);
const databaseUrl = await buildBootstrapDatabaseUrl(
  { ref: payload.ref, password: payload.password, raw: payload.raw },
  mode,
);

const doc = {
  supabase_project_ref: payload.ref,
  supabase_url: payload.supabaseUrl,
  supabase_anon_key: payload.anonKey,
  database_url: databaseUrl,
};

if (jsonMode) {
  process.stdout.write(`${JSON.stringify(doc)}\n`);
} else if (fieldName) {
  const value = doc[fieldName];
  if (value === undefined) {
    die(`unknown field ${fieldName}`, 'extract-bootstrap-fields');
  }
  process.stdout.write(`${value}`);
} else {
  die('pass --json or --field <name>', 'extract-bootstrap-fields');
}

