#!/usr/bin/env node
/**
 * One-time backfill: merge Supabase Management API pooler/direct targets into bootstrap JSON.
 *
 * Usage:
 *   aws secretsmanager get-secret-value ... | node backfill-bootstrap-database-targets.mjs
 *
 * Env (required when pooler host is missing):
 *   REBASE_SUPABASE_ACCESS_TOKEN or SUPABASE_ACCESS_TOKEN
 *   SUPABASE_MANAGEMENT_API_URL (optional, default https://api.supabase.com/v1)
 *
 * Writes merged JSON to stdout. Does not call AWS; repair script persists when changed.
 */
import { readFileSync } from 'node:fs';

import { die, trim } from './build-bootstrap-database-url.mjs';

function managementToken() {
  return trim(process.env.REBASE_SUPABASE_ACCESS_TOKEN) || trim(process.env.SUPABASE_ACCESS_TOKEN);
}

function managementApiBase() {
  return trim(process.env.SUPABASE_MANAGEMENT_API_URL) || 'https://api.supabase.com/v1';
}

function pickPoolerRow(rows, poolMode) {
  if (!Array.isArray(rows)) {
    return null;
  }
  const primary = rows.filter(
    (row) =>
      row &&
      typeof row === 'object' &&
      trim(row.database_type ?? row.databaseType).toUpperCase() === 'PRIMARY',
  );
  const wantMode = poolMode === 'session' ? 'session' : 'transaction';
  const exact = primary.find((row) => trim(row.pool_mode ?? row.poolMode).toLowerCase() === wantMode);
  return exact ?? primary[0] ?? null;
}

async function fetchJson(path) {
  const token = managementToken();
  if (!token) {
    die('REBASE_SUPABASE_ACCESS_TOKEN or SUPABASE_ACCESS_TOKEN is required to backfill database targets');
  }
  const url = `${managementApiBase().replace(/\/$/, '')}${path}`;
  const response = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: 'application/json',
    },
  });
  if (!response.ok) {
    const body = await response.text();
    die(`Supabase API ${path} failed (${response.status}): ${body.slice(0, 300)}`);
  }
  return response.json();
}

const fileIdx = process.argv.indexOf('--file');
let raw = '';
if (fileIdx >= 0) {
  const path = process.argv[fileIdx + 1];
  if (!path) die('--file requires a path');
  raw = readFileSync(path, 'utf8');
} else {
  raw = readFileSync(0, 'utf8');
}

let data;
try {
  data = JSON.parse(raw);
} catch {
  die('bootstrap JSON is not valid JSON');
}
if (!data || typeof data !== 'object') {
  die('bootstrap JSON must be an object');
}

const ref = trim(data.supabase_project_ref ?? data.supabaseProjectRef);
if (!ref) {
  die('missing supabase_project_ref');
}

const hasPooler = Boolean(trim(data.database_pooler_host ?? data.databasePoolerHost));
const hasDirect = Boolean(trim(data.database_direct_host ?? data.databaseDirectHost));

if (hasPooler && hasDirect) {
  process.stdout.write(`${JSON.stringify(data)}\n`);
  process.exit(0);
}

const next = { ...data };

if (!hasPooler) {
  const rows = await fetchJson(`/projects/${ref}/config/database/pooler`);
  const row = pickPoolerRow(rows, 'transaction') ?? pickPoolerRow(rows, 'session');
  if (!row) {
    die(`Supabase pooler config for ${ref} did not include a PRIMARY entry`);
  }
  const host = trim(row.db_host ?? row.dbHost);
  const portRaw = row.db_port ?? row.dbPort;
  const port = typeof portRaw === 'number' ? portRaw : Number.parseInt(trim(String(portRaw ?? '')), 10);
