#!/usr/bin/env node
/**
 * Dry-run DATABASE_URL construction — no AWS/GCP/Secret Manager writes.
 *
 * Wire path (bootstrap secret fields → URL):
 *   node dry-run-database-url.mjs --file bootstrap.json
 *   echo '{"supabase_project_ref":"...","database_password":"...","database_pooler_host":"..."}' | node dry-run-database-url.mjs
 *
 * Provision path (Supabase Management API → secret fields → URL):
 *   REBASE_SUPABASE_ACCESS_TOKEN=sbp_... node dry-run-database-url.mjs --project-ref <ref> --fetch
 *
 * Env:
 *   REBASE_DATABASE_URL_MODE=direct|pooler (default pooler)
 *   REBASE_SUPABASE_ACCESS_TOKEN / SUPABASE_ACCESS_TOKEN (required with --fetch)
 *   SUPABASE_MANAGEMENT_API_URL (optional)
 */
import { readFileSync } from 'node:fs';

import {
  buildBootstrapDatabaseUrl,
  die,
  resolveDatabaseUrlMode,
  trim,
} from './build-bootstrap-database-url.mjs';

function managementToken() {
  return trim(process.env.REBASE_SUPABASE_ACCESS_TOKEN) || trim(process.env.SUPABASE_ACCESS_TOKEN);
}

function managementApiBase() {
  return trim(process.env.SUPABASE_MANAGEMENT_API_URL) || 'https://api.supabase.com/v1';
}

function redactDatabaseUrl(url) {
  return url.replace(/:([^:@/]+)@/, ':***@');
}

function pickPoolerRow(rows, poolMode) {
  if (!Array.isArray(rows)) {
    return null;
  }
  const primary = rows.filter(
    (row) =>
      row &&
      typeof row === 'object' &&
      trim(row.database_type ?? row.databaseType).toUpperCase() === 'PRIMARY',
  );
  const wantMode = poolMode === 'session' ? 'session' : 'transaction';
  const exact = primary.find((row) => trim(row.pool_mode ?? row.poolMode).toLowerCase() === wantMode);
