}

async function fetchJson(path) {
  const token = managementToken();
  if (!token) {
    die('REBASE_SUPABASE_ACCESS_TOKEN or SUPABASE_ACCESS_TOKEN is required with --fetch');
  }
  const url = `${managementApiBase().replace(/\/$/, '')}${path}`;
  const response = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: 'application/json',
    },
  });
  if (!response.ok) {
    const body = await response.text();
    die(`Supabase API ${path} failed (${response.status}): ${body.slice(0, 300)}`);
  }
  return response.json();
}

async function bootstrapFromFetch(projectRef) {
  const ref = trim(projectRef);
  if (!ref) {
    die('--project-ref is required with --fetch');
  }

  const rows = await fetchJson(`/projects/${ref}/config/database/pooler`);
  const poolerRow = pickPoolerRow(rows, 'transaction') ?? pickPoolerRow(rows, 'session');
  if (!poolerRow) {
    die(`Supabase pooler config for ${ref} did not include a PRIMARY entry`);
  }

  const detail = await fetchJson(`/projects/${ref}`);
  const poolerHost = trim(poolerRow.db_host ?? poolerRow.dbHost);
  const poolerPortRaw = poolerRow.db_port ?? poolerRow.dbPort;
  const poolerPort =
    typeof poolerPortRaw === 'number'
      ? poolerPortRaw
      : Number.parseInt(trim(String(poolerPortRaw ?? '')), 10);
  const poolerUser = trim(poolerRow.db_user ?? poolerRow.dbUser) || `postgres.${ref}`;
  const directHost = trim(detail.db_host ?? detail.dbHost) || `db.${ref}.supabase.co`;
  const directPortRaw = detail.db_port ?? detail.dbPort;
  const directPort =
    typeof directPortRaw === 'number'
      ? directPortRaw
